#include <iostream>
#include <iomanip>

struct Rectangle
{
    double width;
    double height;
};

double area(Rectangle r)
{
    return r.width * r.height;
}

int main()
{
    Rectangle r1;
    Rectangle r2;

    std::cin >> r1.width >> r1.height;
    std::cin >> r2.width >> r2.height;

    std::cout << std::fixed << std::setprecision(1);

    std::cout << "Rectangle 1: " << r1.width << " x " << r1.height
              << ", area = " << area(r1) << '\n';
    std::cout << "Rectangle 2: " << r2.width << " x " << r2.height
              << ", area = " << area(r2) << '\n';

    return 0;
}

#include <iostream>
#include <string>

struct Student
{
    std::string name;
    int score1;
    int score2;
    int score3;
};

char letterGrade(int avg)
{
    if (avg >= 90)
        return 'A';
    else if (avg >= 80)
        return 'B';
    else if (avg >= 70)
        return 'C';
    else if (avg >= 60)
        return 'D';
    else
        return 'F';
}

int main()
{
    Student s1;
    Student s2;

    std::cin >> s1.name >> s1.score1 >> s1.score2 >> s1.score3;
    std::cin >> s2.name >> s2.score1 >> s2.score2 >> s2.score3;

    int avg1 = (s1.score1 + s1.score2 + s1.score3) / 3;
    int avg2 = (s2.score1 + s2.score2 + s2.score3) / 3;

    std::cout << s1.name << ": avg = " << avg1
              << ", grade = " << letterGrade(avg1) << '\n';
    std::cout << s2.name << ": avg = " << avg2
              << ", grade = " << letterGrade(avg2) << '\n';

    return 0;
}
